import{_ as t,o as s,c as r,a2 as l}from"./chunks/framework.C58al07P.js";const m=JSON.parse('{"title":"Newsletters et désabonnement","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/newsletters.md","filePath":"fr/guide/newsletters.md"}'),a={name:"fr/guide/newsletters.md"};function n(i,e,o,d,u,c){return s(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="newsletters-et-desabonnement" tabindex="-1">Newsletters et désabonnement <a class="header-anchor" href="#newsletters-et-desabonnement" aria-label="Permalink to &quot;Newsletters et désabonnement&quot;">​</a></h1><p>Nid vous aide à identifier les newsletters et listes de diffusion auxquelles vous êtes abonné, puis à les nettoyer en masse.</p><hr><h2 id="scanner-les-newsletters" tabindex="-1">Scanner les newsletters <a class="header-anchor" href="#scanner-les-newsletters" aria-label="Permalink to &quot;Scanner les newsletters&quot;">​</a></h2><ol><li>Ouvrez la page <strong>Newsletters</strong> dans la sidebar</li><li>Cliquez sur <strong>Scanner</strong> sur le compte Gmail de votre choix</li><li>Un job de scan est lancé — il analyse les headers <code>List-Unsubscribe</code> de vos mails récents</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Newsletters avant le scan, avec le bouton Scanner</em></p></blockquote><hr><h2 id="liste-des-newsletters-detectees" tabindex="-1">Liste des newsletters détectées <a class="header-anchor" href="#liste-des-newsletters-detectees" aria-label="Permalink to &quot;Liste des newsletters détectées&quot;">​</a></h2><p>Après le scan, Nid affiche la liste de toutes les newsletters détectées, avec pour chacune :</p><ul><li><strong>Expéditeur</strong> : l&#39;adresse d&#39;envoi de la newsletter</li><li><strong>Nombre de mails</strong> : combien de mails vous avez reçus de cet expéditeur</li><li><strong>Taille totale</strong> : l&#39;espace occupé par ces mails</li></ul><p>La liste est triée par nombre de mails décroissant, ce qui met en avant les newsletters les plus envahissantes.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : liste des newsletters détectées avec les colonnes expéditeur, nombre de mails et taille</em></p></blockquote><hr><h2 id="voir-les-mails-d-une-newsletter" tabindex="-1">Voir les mails d&#39;une newsletter <a class="header-anchor" href="#voir-les-mails-d-une-newsletter" aria-label="Permalink to &quot;Voir les mails d&#39;une newsletter&quot;">​</a></h2><p>Cliquez sur un expéditeur pour voir la liste de tous les mails reçus de cette newsletter. Vous pouvez ainsi vérifier le contenu avant de décider de nettoyer.</p><hr><h2 id="nettoyer-les-newsletters" tabindex="-1">Nettoyer les newsletters <a class="header-anchor" href="#nettoyer-les-newsletters" aria-label="Permalink to &quot;Nettoyer les newsletters&quot;">​</a></h2><p>Pour chaque newsletter, deux options de suppression sont disponibles :</p><h3 id="envoyer-a-la-corbeille" tabindex="-1">Envoyer à la corbeille <a class="header-anchor" href="#envoyer-a-la-corbeille" aria-label="Permalink to &quot;Envoyer à la corbeille&quot;">​</a></h3><p>Déplace tous les mails de cet expéditeur vers la corbeille Gmail. Les mails sont récupérables pendant 30 jours.</p><h3 id="supprimer-definitivement" tabindex="-1">Supprimer définitivement <a class="header-anchor" href="#supprimer-definitivement" aria-label="Permalink to &quot;Supprimer définitivement&quot;">​</a></h3><p>Supprime définitivement tous les mails de cet expéditeur. Cette action est <strong>irréversible</strong>.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : boutons d&#39;action sur une newsletter (Corbeille / Supprimer définitivement)</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Se désabonner aussi chez l&#39;expéditeur</p><p>Nid détecte les newsletters mais ne gère pas le désabonnement auprès de l&#39;expéditeur lui-même. Ouvrez le dernier mail de la newsletter et cliquez sur le lien de désabonnement en bas du mail pour ne plus recevoir de nouveaux mails.</p></div><hr><h2 id="bonnes-pratiques" tabindex="-1">Bonnes pratiques <a class="header-anchor" href="#bonnes-pratiques" aria-label="Permalink to &quot;Bonnes pratiques&quot;">​</a></h2><ol><li><strong>Scannez régulièrement</strong> pour détecter les nouvelles newsletters</li><li><strong>Commencez par la corbeille</strong> plutôt que la suppression définitive</li><li>Combinez avec une <strong>règle automatique</strong> pour supprimer automatiquement les prochains mails d&#39;une newsletter (voir <a href="./rules.html">Règles</a>)</li></ol>',27)])])}const b=t(a,[["render",n]]);export{m as __pageData,b as default};
